void printVector(std::vector&lt;int&gt; v)
{
    for (int val : v)
        std::cout &lt;&lt; val &lt;&lt; ' ';
}

void addOne(std::vector&lt;int&gt;&amp; v) {
    for (int&amp; val : v)
        val += 1;
}
std::vector&lt;int&gt; v{1, 2, 3};
addOne(v);
std::cout &lt;&lt; v[0];

const std::vector&lt;int&gt;&amp; getVector() {
    std::vector&lt;int&gt; v{1, 2, 3};
    return v;
}
